// components/CameraCapture.js
// In-browser camera capture for desktop (webcam) and mobile (back camera)
// Uses the MediaDevices API — works on all modern browsers

import React, { useState, useRef, useEffect, useCallback } from 'react';
import './CameraCapture.css';

export default function CameraCapture({ onCapture, onClose }) {
  const videoRef    = useRef(null);
  const canvasRef   = useRef(null);
  const streamRef   = useRef(null);

  const [active,     setActive]     = useState(false);
  const [error,      setError]      = useState('');
  const [captured,   setCaptured]   = useState(null);  // base64 preview
  const [facingMode, setFacingMode] = useState('environment'); // back camera default
  const [quality,    setQuality]    = useState(null);  // quality check result

  // Start camera stream
  const startCamera = useCallback(async () => {
    setError('');
    try {
      // Stop any existing stream first
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(t => t.stop());
      }

      const constraints = {
        video: {
          facingMode,
          width:  { ideal: 1920 },
          height: { ideal: 1080 },
        }
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      streamRef.current = stream;

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
        setActive(true);
      }
    } catch (err) {
      if (err.name === 'NotAllowedError') {
        setError('Camera access denied. Please allow camera permission in your browser settings.');
      } else if (err.name === 'NotFoundError') {
        setError('No camera found on this device.');
      } else {
        setError(`Camera error: ${err.message}`);
      }
    }
  }, [facingMode]);

  // Stop stream on unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(t => t.stop());
      }
    };
  }, []);

  // Restart when facing mode changes
  useEffect(() => {
    if (active) startCamera();
  }, [facingMode]); // eslint-disable-line

  // ── Image quality check ────────────────────────────────────────────────────
  const checkQuality = (imageData) => {
    // Laplacian variance for blur detection
    const data   = imageData.data;
    const w      = imageData.width;
    const h      = imageData.height;
    const pixels = [];

    // Sample every 4th pixel for speed
    for (let y = 1; y < h - 1; y += 4) {
      for (let x = 1; x < w - 1; x += 4) {
        const i = (y * w + x) * 4;
        // Grayscale
        const gray = 0.299 * data[i] + 0.587 * data[i+1] + 0.114 * data[i+2];
        // Laplacian kernel: -4*center + top + bottom + left + right
        const top    = 0.299 * data[((y-1)*w+x)*4]   + 0.587 * data[((y-1)*w+x)*4+1]   + 0.114 * data[((y-1)*w+x)*4+2];
        const bottom = 0.299 * data[((y+1)*w+x)*4]   + 0.587 * data[((y+1)*w+x)*4+1]   + 0.114 * data[((y+1)*w+x)*4+2];
        const left   = 0.299 * data[(y*w+(x-1))*4]   + 0.587 * data[(y*w+(x-1))*4+1]   + 0.114 * data[(y*w+(x-1))*4+2];
        const right  = 0.299 * data[(y*w+(x+1))*4]   + 0.587 * data[(y*w+(x+1))*4+1]   + 0.114 * data[(y*w+(x+1))*4+2];
        pixels.push(Math.abs(-4 * gray + top + bottom + left + right));
      }
    }

    const mean     = pixels.reduce((a, b) => a + b, 0) / pixels.length;
    const variance = pixels.reduce((a, b) => a + (b - mean) ** 2, 0) / pixels.length;

    // Brightness check
    let totalBrightness = 0;
    let sampleCount     = 0;
    for (let i = 0; i < data.length; i += 16) {
      totalBrightness += 0.299 * data[i] + 0.587 * data[i+1] + 0.114 * data[i+2];
      sampleCount++;
    }
    const avgBrightness = totalBrightness / sampleCount;

    const isBlurry    = variance < 100;
    const isDark      = avgBrightness < 60;
    const isBright    = avgBrightness > 220;
    const isGood      = !isBlurry && !isDark && !isBright;

    return {
      isGood,
      isBlurry,
      isDark,
      isBright,
      variance:   Math.round(variance),
      brightness: Math.round(avgBrightness),
      score:      Math.min(100, Math.round(variance / 5)),
    };
  };

  // ── Capture photo ──────────────────────────────────────────────────────────
  const capturePhoto = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const video  = videoRef.current;
    const canvas = canvasRef.current;
    canvas.width  = video.videoWidth;
    canvas.height = video.videoHeight;

    const ctx = canvas.getContext('2d');
    ctx.drawImage(video, 0, 0);

    // Quality check
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const q         = checkQuality(imageData);
    setQuality(q);

    const dataUrl = canvas.toDataURL('image/jpeg', 0.92);
    setCaptured(dataUrl);

    // Stop camera preview
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop());
      setActive(false);
    }
  };

  // ── Use photo ──────────────────────────────────────────────────────────────
  const usePhoto = () => {
    if (!captured || !canvasRef.current) return;
    canvasRef.current.toBlob(blob => {
      const file = new File([blob], `capture_${Date.now()}.jpg`, { type: 'image/jpeg' });
      onCapture(file);
      onClose();
    }, 'image/jpeg', 0.92);
  };

  const retake = () => {
    setCaptured(null);
    setQuality(null);
    startCamera();
  };

  return (
    <div className="camera-overlay" onClick={onClose}>
      <div className="camera-modal" onClick={e => e.stopPropagation()}>

        {/* Header */}
        <div className="camera-header">
          <h2>Capture Answer Sheet</h2>
          <button className="camera-close" onClick={onClose}>✕</button>
        </div>

        {/* Error state */}
        {error && (
          <div className="camera-error">
            <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
              <circle cx="9" cy="9" r="7" stroke="currentColor" strokeWidth="1.5"/>
              <path d="M9 6v3.5M9 12v.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
            </svg>
            <span>{error}</span>
          </div>
        )}

        {/* Not started */}
        {!active && !captured && !error && (
          <div className="camera-start">
            <div className="camera-icon">
              <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
                <rect x="4" y="12" width="40" height="28" rx="4"
                  stroke="var(--accent)" strokeWidth="1.5" fill="var(--accent-glow)"/>
                <circle cx="24" cy="26" r="8" stroke="var(--accent)" strokeWidth="1.5"/>
                <circle cx="24" cy="26" r="4" fill="var(--accent)"/>
                <path d="M17 12l2.5-4h9l2.5 4" stroke="var(--accent)"
                  strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            </div>
            <p>Position the answer sheet flat with good lighting before capturing.</p>
            <button className="btn btn-primary btn-lg" onClick={startCamera}>
              Open Camera
            </button>
          </div>
        )}

        {/* Live camera view */}
        {active && !captured && (
          <div className="camera-live">
            <div className="camera-viewfinder">
              <video ref={videoRef} className="camera-video"
                autoPlay playsInline muted />
              <div className="camera-guide">
                <div className="guide-corner tl" />
                <div className="guide-corner tr" />
                <div className="guide-corner bl" />
                <div className="guide-corner br" />
                <span className="guide-label">Align paper within frame</span>
              </div>
            </div>
            <div className="camera-controls">
              <button className="btn-cam-flip" onClick={() =>
                setFacingMode(f => f === 'environment' ? 'user' : 'environment')}
                title="Flip camera">
                <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                  <path d="M3 10a7 7 0 0 1 13-3.5M17 10a7 7 0 0 1-13 3.5"
                    stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                  <path d="M16 4l1 2.5-2.5 1M4 16l-1-2.5 2.5-1"
                    stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>
              <button className="btn-shutter" onClick={capturePhoto}>
                <div className="shutter-inner" />
              </button>
              <div style={{ width: 44 }} />
            </div>
          </div>
        )}

        {/* Preview after capture */}
        {captured && (
          <div className="camera-preview">
            <div className="camera-preview-img-wrap">
              <img src={captured} alt="Captured" className="camera-preview-img" />
              {quality && (
                <div className={`quality-badge ${quality.isGood ? 'q-good' : 'q-warn'}`}>
                  {quality.isGood ? '✓ Good quality' :
                   quality.isBlurry ? '⚠ Blurry — retake recommended' :
                   quality.isDark   ? '⚠ Too dark — needs more light' :
                                      '⚠ Overexposed — reduce light'}
                </div>
              )}
            </div>

            {quality && (
              <div className="quality-stats">
                <div className="q-stat">
                  <span className="q-stat-label">Sharpness</span>
                  <div className="q-bar-track">
                    <div className="q-bar-fill"
                      style={{
                        width: `${Math.min(quality.score, 100)}%`,
                        background: quality.isBlurry ? 'var(--danger)' : 'var(--accent)'
                      }} />
                  </div>
                  <span className="q-stat-val">{quality.score}/100</span>
                </div>
                <div className="q-stat">
                  <span className="q-stat-label">Brightness</span>
                  <div className="q-bar-track">
                    <div className="q-bar-fill"
                      style={{
                        width: `${(quality.brightness / 255) * 100}%`,
                        background: (quality.isDark || quality.isBright)
                          ? 'var(--danger)' : 'var(--accent)'
                      }} />
                  </div>
                  <span className="q-stat-val">{quality.brightness}/255</span>
                </div>
              </div>
            )}

            <div className="camera-preview-actions">
              <button className="btn btn-ghost" onClick={retake}>Retake</button>
              <button className="btn btn-primary" onClick={usePhoto}>
                Use Photo
              </button>
            </div>
          </div>
        )}

        {/* Hidden canvas for capture */}
        <canvas ref={canvasRef} style={{ display: 'none' }} />
      </div>
    </div>
  );
}
